     1→'use client';
     2→
     3→/**
     4→ * FocusToolLayout - Fullscreen layout for working with tools
     5→ *
     6→ * Layout:
     7→ * - Left (1/3): Chat with maestro/coach
     8→ * - Right (2/3): Tool panel (mindmap, quiz, etc.)
     9→ * - Header: Minimal with exit button
    10→ * - ESC to exit
    11→ */
    12→
    13→import { useEffect, useCallback, useState, useRef } from 'react';
    14→import { motion, AnimatePresence } from 'framer-motion';
    15→import { X, Loader2, Send, Mic, MicOff, Phone, PhoneOff, Volume2 } from 'lucide-react';
    16→import { Button } from '@/components/ui/button';
    17→import { ToolPanel } from './tool-panel';
    18→import { useUIStore, useSettingsStore } from '@/lib/stores/app-store';
    19→import { getMaestroById } from '@/data/maestri';
    20→import { getSupportTeacherById } from '@/data/support-teachers';
    21→import { useVoiceSession } from '@/lib/hooks/use-voice-session';
    22→import { logger } from '@/lib/logger';
    23→import type { ToolType } from '@/types/tools';
    24→import type { MaestroFull } from '@/data/maestri';
    25→import type { SupportTeacher, Subject } from '@/types';
    26→import { cn } from '@/lib/utils';
    27→
    28→// Map tool types to suggested maestros (for future use)
    29→const _TOOL_TO_MAESTRO: Record<ToolType, string> = {
    30→  mindmap: 'melissa', // Coach for general organization
    31→  quiz: 'melissa',
    32→  flashcard: 'melissa',
    33→  summary: 'melissa',
    34→  demo: 'ada', // Ada for demos/coding
    35→  diagram: 'euclid', // Euclid for diagrams
    36→  timeline: 'herodotus', // Herodotus for timelines
    37→  formula: 'euclid',
    38→  chart: 'euclid',
    39→  search: 'melissa',
    40→  webcam: 'melissa',
    41→  pdf: 'melissa',
    42→  homework: 'melissa',
    43→};
    44→
    45→// Map subjects to maestros (for future use)
    46→const _SUBJECT_TO_MAESTRO: Record<string, string> = {
    47→  mathematics: 'euclid',
    48→  math: 'euclid',
    49→  matematica: 'euclid',
    50→  history: 'herodotus',
    51→  storia: 'herodotus',
    52→  italian: 'manzoni',
    53→  italiano: 'manzoni',
    54→  english: 'shakespeare',
    55→  inglese: 'shakespeare',
    56→  physics: 'feynman',
    57→  fisica: 'feynman',
    58→  chemistry: 'curie',
    59→  chimica: 'curie',
    60→  biology: 'darwin',
    61→  biologia: 'darwin',
    62→  scienze: 'darwin',
    63→  geography: 'humboldt',
    64→  geografia: 'humboldt',
    65→  art: 'davinci',
    66→  arte: 'davinci',
    67→  music: 'mozart',
    68→  musica: 'mozart',
    69→  philosophy: 'socrates',
    70→  filosofia: 'socrates',
    71→  economics: 'smith',
    72→  economia: 'smith',
    73→  civics: 'cicero',
    74→  educazione_civica: 'cicero',
    75→  pe: 'hippocrates',
    76→  educazione_fisica: 'hippocrates',
    77→  coding: 'ada',
    78→  informatica: 'ada',
    79→  storytelling: 'chris',
    80→};
    81→
    82→interface Message {
    83→  id: string;
    84→  role: 'user' | 'assistant';
    85→  content: string;
    86→  timestamp: Date;
    87→}
    88→
    89→// Map function names to tool types
    90→const FUNCTION_NAME_TO_TOOL_TYPE: Record<string, ToolType> = {
    91→  create_mindmap: 'mindmap',
    92→  create_quiz: 'quiz',
    93→  create_demo: 'demo',
    94→  web_search: 'search',
    95→  create_flashcards: 'flashcard',
    96→  create_diagram: 'diagram',
    97→  create_timeline: 'timeline',
    98→  create_summary: 'summary',
    99→  open_student_summary: 'summary',
   100→};
   101→
   102→export function FocusToolLayout() {
   103→  const { focusMode, focusToolType, focusMaestroId, focusInteractionMode, focusTool, setFocusTool, exitFocusMode } = useUIStore();
   104→  const { studentProfile } = useSettingsStore();
   105→
   106→  const [messages, setMessages] = useState<Message[]>([]);
   107→  const [input, setInput] = useState('');
   108→  const [isLoading, setIsLoading] = useState(false);
   109→  const [isVoiceActive, setIsVoiceActive] = useState(false);
   110→  const [connectionInfo, setConnectionInfo] = useState<{ provider: 'azure'; proxyPort: number; configured: boolean } | null>(null);
   111→  const [configError, setConfigError] = useState<string | null>(null);
   112→  const messagesEndRef = useRef<HTMLDivElement>(null);
   113→  const inputRef = useRef<HTMLInputElement>(null);
   114→  const lastTranscriptIdRef = useRef<string | null>(null);
   115→
   116→  // Determine which maestro/coach to use
   117→  const getMaestroOrCoach = useCallback((): MaestroFull | SupportTeacher | null => {
   118→    // If specific maestro requested
   119→    if (focusMaestroId) {
   120→      const maestro = getMaestroById(focusMaestroId);
   121→      if (maestro) return maestro;
   122→
   123→      // Check if it's a coach
   124→      const coach = getSupportTeacherById(focusMaestroId as 'melissa' | 'roberto' | 'chiara' | 'andrea' | 'favij');
   125→      if (coach) return coach;
   126→    }
   127→
   128→    // Default to coach based on preference or tool type
   129→    const preferredCoach = studentProfile?.preferredCoach || 'melissa';
   130→    const coach = getSupportTeacherById(preferredCoach);
   131→    if (coach) return coach;
   132→
   133→    return null;
   134→  }, [focusMaestroId, studentProfile?.preferredCoach]);
   135→
   136→  const character = getMaestroOrCoach();
   137→
   138→  // Helper to get display properties from either MaestroFull or SupportTeacher
   139→  const getCharacterProps = (char: MaestroFull | SupportTeacher | null) => {
   140→    if (!char) return null;
   141→    // MaestroFull has displayName, SupportTeacher has name
   142→    const isMaestro = 'displayName' in char;
   143→    return {
   144→      name: isMaestro ? (char as MaestroFull).displayName : char.name,
   145→      avatar: char.avatar || '/avatars/default.jpg',
   146→      color: char.color,
   147→      systemPrompt: char.systemPrompt,
   148→      greeting: char.greeting,
   149→    };
   150→  };
   151→
   152→  const characterProps = getCharacterProps(character);
   153→
   154→  // Voice session hook - must be after character is defined
   155→  const {
   156→    isConnected: voiceConnected,
   157→    isListening,
   158→    isSpeaking,
   159→    isMuted,
   160→    inputLevel,
   161→    connectionState,
   162→    connect: voiceConnect,
   163→    disconnect: voiceDisconnect,
   164→    toggleMute,
   165→    sessionId: voiceSessionId,
   166→  } = useVoiceSession({
   167→    onError: (error) => {
   168→      const message = error instanceof Error ? error.message : String(error);
   169→      logger.error('Voice session error in focus mode', { message });
   170→      setConfigError(message || 'Errore di connessione vocale');
   171→    },
   172→    onTranscript: (role, text) => {
   173→      // Add voice transcripts to messages
   174→      const transcriptId = `voice-${role}-${Date.now()}`;
   175→
   176→      // Avoid duplicate transcripts
   177→      if (lastTranscriptIdRef.current === text.substring(0, 50)) {
   178→        return;
   179→      }
   180→      lastTranscriptIdRef.current = text.substring(0, 50);
   181→
   182→      setMessages(prev => [...prev, {
   183→        id: transcriptId,
   184→        role,
   185→        content: text,
   186→        timestamp: new Date(),
   187→      }]);
   188→    },
   189→  });
   190→
   191→  // Fetch voice connection info on mount
   192→  useEffect(() => {
   193→    async function fetchConnectionInfo() {
   194→      try {
   195→        const response = await fetch('/api/realtime/token');
   196→        const data = await response.json();
   197→        if (data.error) {
   198→          logger.error('Voice API error', { error: data.error });
   199→          setConfigError(data.message || 'Servizio vocale non configurato');
   200→          return;
   201→        }
   202→        setConnectionInfo(data);
   203→      } catch (error) {
   204→        logger.error('Failed to get voice connection info', { error: String(error) });
   205→        setConfigError('Impossibile connettersi al servizio vocale');
   206→      }
   207→    }
   208→    if (focusMode) {
   209→      fetchConnectionInfo();
   210→    }
   211→  }, [focusMode]);
   212→
   213→  // Auto-start voice if interaction mode is 'voice'
   214→  useEffect(() => {
   215→    if (focusMode && focusInteractionMode === 'voice' && connectionInfo && !isVoiceActive) {
   216→      setIsVoiceActive(true);
   217→    }
   218→  }, [focusMode, focusInteractionMode, connectionInfo, isVoiceActive]);
   219→
   220→  // Connect to voice when activated
   221→  useEffect(() => {
   222→    if (!isVoiceActive || !connectionInfo || connectionState !== 'idle' || !character) return;
   223→
   224→    const startVoice = async () => {
   225→      setConfigError(null);
   226→      try {
   227→        // Check if character is a SupportTeacher (has voice property directly)
   228→        const isSupportTeacher = 'voice' in character && 'voiceInstructions' in character;
   229→        // Create a maestro-compatible object for the voice session
   230→        const maestroForVoice = {
   231→          id: character.id,
   232→          name: characterProps?.name || 'Coach',
   233→          subject: ('subject' in character ? character.subject : 'general') as Subject,
   234→          specialty: '',
   235→          voice: isSupportTeacher ? (character as SupportTeacher).voice : 'alloy' as const,
   236→          voiceInstructions: isSupportTeacher ? (character as SupportTeacher).voiceInstructions : 'Parla in modo chiaro e amichevole.',
   237→          teachingStyle: 'Interattivo e coinvolgente',
   238→          avatar: characterProps?.avatar || '/avatars/default.jpg',
   239→          color: characterProps?.color || '#3b82f6',
   240→          systemPrompt: characterProps?.systemPrompt || '',
   241→          greeting: characterProps?.greeting || '',
   242→        };
   243→        await voiceConnect(maestroForVoice, connectionInfo);
   244→      } catch (error) {
   245→        logger.error('Voice connection failed', { error: String(error) });
   246→        if (error instanceof DOMException && error.name === 'NotAllowedError') {
   247→          setConfigError('Microfono non autorizzato. Abilita il microfono nelle impostazioni del browser.');
   248→        } else {
   249→          setConfigError('Errore di connessione vocale');
   250→        }
   251→        setIsVoiceActive(false);
   252→      }
   253→    };
   254→
   255→    startVoice();
   256→  }, [isVoiceActive, connectionInfo, connectionState, character, characterProps, voiceConnect]);
   257→
   258→  // Handle voice toggle
   259→  const handleVoiceToggle = useCallback(() => {
   260→    if (isVoiceActive) {
   261→      voiceDisconnect();
   262→      setIsVoiceActive(false);
   263→    } else {
   264→      setIsVoiceActive(true);
   265→    }
   266→  }, [isVoiceActive, voiceDisconnect]);
   267→
   268→  // ESC key handler
   269→  useEffect(() => {
   270→    const handleKeyDown = (e: KeyboardEvent) => {
   271→      if (e.key === 'Escape' && focusMode) {
   272→        exitFocusMode();
   273→      }
   274→    };
   275→
   276→    window.addEventListener('keydown', handleKeyDown);
   277→    return () => window.removeEventListener('keydown', handleKeyDown);
   278→  }, [focusMode, exitFocusMode]);
   279→
   280→  // Auto-scroll messages
   281→  useEffect(() => {
   282→    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
   283→  }, [messages]);
   284→
   285→  // Focus input when mode activates
   286→  useEffect(() => {
   287→    if (focusMode) {
   288→      inputRef.current?.focus();
   289→    }
   290→  }, [focusMode]);
   291→
   292→  // Initial greeting message
   293→  useEffect(() => {
   294→    if (focusMode && characterProps && messages.length === 0) {
   295→      const toolNames: Record<ToolType, string> = {
   296→        mindmap: 'mappa mentale',
   297→        quiz: 'quiz',
   298→        flashcard: 'flashcard',
   299→        summary: 'riassunto',
   300→        demo: 'demo interattiva',
   301→        diagram: 'diagramma',
   302→        timeline: 'linea del tempo',
   303→        formula: 'formula',
   304→        chart: 'grafico',
   305→        search: 'ricerca',
   306→        webcam: 'foto',
   307→        pdf: 'PDF',
   308→        homework: 'compiti',
   309→      };
   310→
   311→      const toolName = focusToolType ? toolNames[focusToolType] : 'strumento';
   312→
   313→      setMessages([{
   314→        id: 'greeting',
   315→        role: 'assistant',
   316→        content: `Ciao! Sono ${characterProps.name}. Creiamo insieme una ${toolName}! Di che argomento vuoi parlare?`,
   317→        timestamp: new Date(),
   318→      }]);
   319→    }
   320→  }, [focusMode, characterProps, focusToolType, messages.length]);
   321→
   322→  // Handle sending message
   323→  const handleSend = useCallback(async () => {
   324→    if (!input.trim() || isLoading || !character || !characterProps) return;
   325→
   326→    const userMessage = input.trim();
   327→    setInput('');
   328→    setIsLoading(true);
   329→
   330→    const newUserMessage: Message = {
   331→      id: `user-${Date.now()}`,
   332→      role: 'user',
   333→      content: userMessage,
   334→      timestamp: new Date(),
   335→    };
   336→
   337→    setMessages(prev => [...prev, newUserMessage]);
   338→
   339→    try {
   340→      const response = await fetch('/api/chat', {
   341→        method: 'POST',
   342→        headers: { 'Content-Type': 'application/json' },
   343→        body: JSON.stringify({
   344→          messages: [
   345→            ...messages.map(m => ({ role: m.role, content: m.content })),
   346→            { role: 'user', content: userMessage },
   347→          ],
   348→          systemPrompt: characterProps.systemPrompt,
   349→          maestroId: character.id,
   350→          enableTools: true,
   351→          requestedTool: focusToolType,
   352→        }),
   353→      });
   354→
   355→      if (!response.ok) throw new Error('Failed to send message');
   356→
   357→      const data = await response.json();
   358→
   359→      const assistantMessage: Message = {
   360→        id: `assistant-${Date.now()}`,
   361→        role: 'assistant',
   362→        content: data.content || '',
   363→        timestamp: new Date(),
   364→      };
   365→
   366→      if (data.content) {
   367→        setMessages(prev => [...prev, assistantMessage]);
   368→      }
   369→
   370→      // Handle tool calls if any
   371→      if (data.toolCalls && data.toolCalls.length > 0) {
   372→        const toolCall = data.toolCalls[0];
   373→        const toolType = FUNCTION_NAME_TO_TOOL_TYPE[toolCall.type] || focusToolType || 'mindmap';
   374→        const toolContent = toolCall.result?.data || toolCall.result || toolCall.arguments;
   375→
   376→        setFocusTool({
   377→          id: toolCall.id || `tool-${Date.now()}`,
   378→          type: toolType,
   379→          status: 'completed',
   380→          progress: 1,
   381→          content: toolContent,
   382→          createdAt: new Date(),
   383→        });
   384→      }
   385→    } catch (error) {
   386→      logger.error('Chat error in focus mode', { error });
   387→      setMessages(prev => [...prev, {
   388→        id: `error-${Date.now()}`,
   389→        role: 'assistant',
   390→        content: 'Mi dispiace, c\'è stato un errore. Riprova!',
   391→        timestamp: new Date(),
   392→      }]);
   393→    } finally {
   394→      setIsLoading(false);
   395→    }
   396→  }, [input, isLoading, character, characterProps, messages, focusToolType, setFocusTool]);
   397→
   398→  const handleKeyPress = (e: React.KeyboardEvent) => {
   399→    if (e.key === 'Enter' && !e.shiftKey) {
   400→      e.preventDefault();
   401→      handleSend();
   402→    }
   403→  };
   404→
   405→  if (!focusMode) return null;
   406→
   407→  return (
   408→    <AnimatePresence>
   409→      <motion.div
   410→        initial={{ opacity: 0 }}
   411→        animate={{ opacity: 1 }}
   412→        exit={{ opacity: 0 }}
   413→        className="fixed inset-0 z-50 bg-white dark:bg-slate-950"
   414→      >
   415→        {/* Header */}
   416→        <header className="h-14 flex items-center justify-between px-4 border-b border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900">
   417→          <div className="flex items-center gap-3">
   418→            {characterProps && (
   419→              <>
   420→                <div
   421→                  className="w-8 h-8 rounded-full bg-cover bg-center"
   422→                  style={{ backgroundImage: `url(${characterProps.avatar})` }}
   423→                />
   424→                <span className="font-semibold text-slate-900 dark:text-white">
   425→                  {characterProps.name}
   426→                </span>
   427→                <span className="text-sm text-slate-500">
   428→                  • {focusToolType ? focusToolType.charAt(0).toUpperCase() + focusToolType.slice(1) : 'Tool'}
   429→                </span>
   430→              </>
   431→            )}
   432→          </div>
   433→          <div className="flex items-center gap-2">
   434→            {/* Voice status indicator */}
   435→            {focusInteractionMode === 'voice' && (
   436→              <div className={cn(
   437→                'flex items-center gap-1.5 px-2 py-1 rounded-full text-xs font-medium',
   438→                voiceConnected && !isMuted && 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400',
   439→                voiceConnected && isMuted && 'bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-400',
   440→                !voiceConnected && isVoiceActive && 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400',
   441→                configError && 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400'
   442→              )}>
   443→                {configError ? (
   444→                  <>
   445→                    <MicOff className="h-3 w-3" />
   446→                    <span>Voce non disponibile</span>
   447→                  </>
   448→                ) : voiceConnected ? (
   449→                  <>
   450→                    {isMuted ? <MicOff className="h-3 w-3" /> : isSpeaking ? <Volume2 className="h-3 w-3" /> : <Mic className="h-3 w-3" />}
   451→                    <span>{isMuted ? 'Muted' : isSpeaking ? 'Parlando' : 'Voce attiva'}</span>
   452→                  </>
   453→                ) : isVoiceActive ? (
   454→                  <>
   455→                    <Loader2 className="h-3 w-3 animate-spin" />
   456→                    <span>Connessione...</span>
   457→                  </>
   458→                ) : null}
   459→              </div>
   460→            )}
   461→            <span className="text-xs text-slate-400">ESC per uscire</span>
   462→            <Button
   463→              variant="ghost"
   464→              size="icon"
   465→              onClick={exitFocusMode}
   466→              aria-label="Chiudi"
   467→            >
   468→              <X className="h-5 w-5" />
   469→            </Button>
   470→          </div>
   471→        </header>
   472→
   473→        {/* Main content */}
   474→        <div className="flex h-[calc(100vh-56px)]">
   475→          {/* Left: Chat panel (1/3) */}
   476→          <div className="w-1/3 flex flex-col border-r border-slate-200 dark:border-slate-800">
   477→            {/* Messages */}
   478→            <div className="flex-1 overflow-y-auto p-4 space-y-4">
   479→              {messages.map((message) => (
   480→                <div
   481→                  key={message.id}
   482→                  className={cn(
   483→                    'flex',
   484→                    message.role === 'user' ? 'justify-end' : 'justify-start'
   485→                  )}
   486→                >
   487→                  <div
   488→                    className={cn(
   489→                      'max-w-[85%] rounded-2xl px-4 py-2',
   490→                      message.role === 'user'
   491→                        ? 'bg-accent-themed text-white rounded-br-md'
   492→                        : 'bg-slate-100 dark:bg-slate-800 rounded-bl-md'
   493→                    )}
   494→                  >
   495→                    <p className="text-sm whitespace-pre-wrap">{message.content}</p>
   496→                  </div>
   497→                </div>
   498→              ))}
   499→              {isLoading && (
   500→                <div className="flex justify-start">
   501→                  <div className="bg-slate-100 dark:bg-slate-800 rounded-2xl rounded-bl-md px-4 py-2">
   502→                    <Loader2 className="h-4 w-4 animate-spin" />
   503→                  </div>
   504→                </div>
   505→              )}
   506→              <div ref={messagesEndRef} />
   507→            </div>
   508→
   509→            {/* Input */}
   510→            <div className="p-4 border-t border-slate-200 dark:border-slate-700">
   511→              <div className="flex items-center gap-2">
   512→                <input
   513→                  ref={inputRef}
   514→                  type="text"
   515→                  value={input}
   516→                  onChange={(e) => setInput(e.target.value)}
   517→                  onKeyDown={handleKeyPress}
   518→                  placeholder={`Scrivi a ${characterProps?.name || 'Coach'}...`}
   519→                  className="flex-1 px-4 py-2 bg-slate-100 dark:bg-slate-800 rounded-xl border-0 focus:ring-2 focus:ring-accent-themed outline-none text-sm"
   520→                  disabled={isLoading}
   521→                />
   522→                {/* Voice button with status */}
   523→                <div className="relative">
   524→                  {/* Input level indicator */}
   525→                  {voiceConnected && !isMuted && (
   526→                    <div
   527→                      className="absolute -top-1 left-1/2 -translate-x-1/2 w-6 h-1 bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden"
   528→                    >
   529→                      <div
   530→                        className="h-full bg-green-500 transition-all duration-75"
   531→                        style={{ width: `${Math.min(inputLevel * 100, 100)}%` }}
   532→                      />
   533→                    </div>
   534→                  )}
   535→                  <Button
   536→                    variant="ghost"
   537→                    size="icon"
   538→                    onClick={handleVoiceToggle}
   539→                    disabled={!!configError && !isVoiceActive}
   540→                    aria-label={isVoiceActive ? 'Disattiva voce' : 'Attiva voce'}
   541→                    className={cn(
   542→                      'relative',
   543→                      voiceConnected && isSpeaking && 'bg-amber-100 text-amber-600 dark:bg-amber-900/30 dark:text-amber-400',
   544→                      voiceConnected && isListening && !isSpeaking && 'bg-green-100 text-green-600 dark:bg-green-900/30 dark:text-green-400',
   545→                      voiceConnected && isMuted && 'bg-slate-200 text-slate-500 dark:bg-slate-700',
   546→                      !voiceConnected && isVoiceActive && 'bg-blue-100 text-blue-600 animate-pulse',
   547→                      configError && 'bg-red-100 text-red-600'
   548→                    )}
   549→                    title={configError || (voiceConnected ? (isMuted ? 'Muted' : isSpeaking ? 'Parlando...' : isListening ? 'Ascoltando...' : 'Connesso') : 'Attiva voce')}
   550→                  >
   551→                    {voiceConnected ? (
   552→                      isMuted ? <MicOff className="h-4 w-4" /> : isSpeaking ? <Volume2 className="h-4 w-4" /> : <Phone className="h-4 w-4" />
   553→                    ) : isVoiceActive ? (
   554→                      <Loader2 className="h-4 w-4 animate-spin" />
