     1→/**
     2→ * ConvergioEdu Conversation Flow Store
     3→ *
     4→ * Manages the state of the conversation-first interface:
     5→ * - Current active character (Coach, Maestro, Buddy)
     6→ * - SEPARATE conversations per character (#33)
     7→ * - Character routing and handoffs
     8→ *
     9→ * Part of I-01: Conversation-First Main Flow
    10→ * Related: #24 MirrorBuddy Issue, #33 Separate Conversations, ManifestoEdu.md
    11→ */
    12→
    13→import { create } from 'zustand';
    14→import type { CharacterType, ExtendedStudentProfile } from '@/types';
    15→import type { MaestroFull } from '@/data/maestri';
    16→import type { SupportTeacher } from '@/types';
    17→import type { BuddyProfile } from '@/types';
    18→import {
    19→  routeToCharacter,
    20→  getCharacterGreeting as _getCharacterGreeting,
    21→  getCharacterSystemPrompt as _getCharacterSystemPrompt,
    22→  type RoutingResult,
    23→} from '@/lib/ai/character-router';
    24→import { getDefaultSupportTeacher, getSupportTeacherById, type CoachId } from '@/data/support-teachers';
    25→import { getBuddyForStudent } from '@/lib/ai/character-router';
    26→import { getBuddyById, type BuddyId } from '@/data/buddy-profiles';
    27→import { getMaestroById } from '@/data/maestri';
    28→import { logger } from '@/lib/logger';
    29→import { inactivityMonitor } from '@/lib/conversation/inactivity-monitor';
    30→import { endConversationWithSummary as generateSummary } from '@/lib/conversation/summary-generator';
    31→import { getGreetingForCharacter } from '@/lib/conversation/contextual-greeting';
    32→
    33→// ============================================================================
    34→// PERSISTENCE HELPERS
    35→// ============================================================================
    36→
    37→/**
    38→ * Create a new conversation in the database.
    39→ */
    40→async function createConversationInDB(
    41→  characterId: string,
    42→  characterType: CharacterType,
    43→  characterName: string
    44→): Promise<string | null> {
    45→  try {
    46→    const response = await fetch('/api/conversations', {
    47→      method: 'POST',
    48→      headers: { 'Content-Type': 'application/json' },
    49→      body: JSON.stringify({
    50→        maestroId: characterId,
    51→        title: `Conversazione con ${characterName}`,
    52→      }),
    53→    });
    54→    if (!response.ok) {
    55→      logger.error('Failed to create conversation', { status: response.status });
    56→      return null;
    57→    }
    58→    const data = await response.json();
    59→    logger.debug('Created conversation', { id: data.id, characterId });
    60→    return data.id;
    61→  } catch (error) {
    62→    logger.error('Error creating conversation', { error: String(error) });
    63→    return null;
    64→  }
    65→}
    66→
    67→/**
    68→ * Save a message to the database.
    69→ */
    70→async function saveMessageToDB(
    71→  conversationId: string,
    72→  role: string,
    73→  content: string
    74→): Promise<void> {
    75→  try {
    76→    const response = await fetch(`/api/conversations/${conversationId}/messages`, {
    77→      method: 'POST',
    78→      headers: { 'Content-Type': 'application/json' },
    79→      body: JSON.stringify({ role, content }),
    80→    });
    81→    if (!response.ok) {
    82→      logger.error('Failed to save message', { status: response.status });
    83→    }
    84→  } catch (error) {
    85→    logger.error('Error saving message', { error: String(error) });
    86→  }
    87→}
    88→
    89→/**
    90→ * Conversation summary from DB (used for context, not full message restoration).
    91→ */
    92→interface ConversationSummary {
    93→  id: string;
    94→  maestroId: string;
    95→  title: string;
    96→  summary: string | null;
    97→  keyFacts: string[] | null;
    98→  topics: string[];
    99→  messageCount: number;
   100→  lastMessageAt: string | null;
   101→}
   102→
   103→/**
   104→ * Load conversation summaries from the database (not full messages).
   105→ * We use summaries for context instead of restoring entire conversations.
   106→ */
   107→async function loadConversationSummariesFromDB(): Promise<ConversationSummary[]> {
   108→  try {
   109→    const response = await fetch('/api/conversations?limit=20&active=true');
   110→
   111→    // 401 = no user cookie yet (first visit), not an error
   112→    if (response.status === 401) {
   113→      return [];
   114→    }
   115→
   116→    if (!response.ok) {
   117→      logger.warn('Conversations API returned error', { status: response.status });
   118→      return [];
   119→    }
   120→
   121→    const data = await response.json();
   122→
   123→    // API might return error object instead of array
   124→    if (!Array.isArray(data)) {
   125→      if (data.error) {
   126→        logger.warn('Conversations API error', { error: data.error });
   127→      }
   128→      return [];
   129→    }
   130→
   131→    return data;
   132→  } catch (error) {
   133→    // Network error or JSON parse error
   134→    logger.warn('Error loading conversation summaries', { error: String(error) });
   135→    return [];
   136→  }
   137→}
   138→
   139→/**
   140→ * Update conversation summary in DB.
   141→ * NOTE: Integrate with conversation-flow.tsx endSession() for memory persistence.
   142→ * See ADR-0021 for architecture details.
   143→ */
   144→async function _updateConversationSummary(
   145→  conversationId: string,
   146→  summary: string,
   147→  keyFacts: string[],
   148→  topics: string[]
   149→): Promise<void> {
   150→  try {
   151→    await fetch(`/api/conversations/${conversationId}`, {
   152→      method: 'PUT',
   153→      headers: { 'Content-Type': 'application/json' },
   154→      body: JSON.stringify({ summary, keyFacts: JSON.stringify(keyFacts), topics }),
   155→    });
   156→  } catch (error) {
   157→    logger.error('Error updating conversation summary', { error: String(error) });
   158→  }
   159→}
   160→
   161→// ============================================================================
   162→// TYPES
   163→// ============================================================================
   164→
   165→/**
   166→ * Active character in the conversation.
   167→ */
   168→export interface ActiveCharacter {
   169→  type: CharacterType;
   170→  id: string;
   171→  name: string;
   172→  character: MaestroFull | SupportTeacher | BuddyProfile;
   173→  greeting: string;
   174→  systemPrompt: string;
   175→  color: string;
   176→  voice: string;
   177→  voiceInstructions: string;
   178→  subtitle?: string;
   179→}
   180→
   181→/**
   182→ * A message in the conversation flow.
   183→ */
   184→export interface FlowMessage {
   185→  id: string;
   186→  role: 'user' | 'assistant' | 'system';
   187→  content: string;
   188→  timestamp: Date;
   189→  characterId?: string;
   190→  characterType?: CharacterType;
   191→  /** If this message triggered a character switch */
   192→  switchedTo?: {
   193→    type: CharacterType;
   194→    id: string;
   195→    reason: string;
   196→  };
   197→}
   198→
   199→/**
   200→ * Stored conversation for a character.
   201→ */
   202→export interface CharacterConversation {
   203→  characterId: string;
   204→  characterType: CharacterType;
   205→  characterName: string;
   206→  messages: FlowMessage[];
   207→  lastMessageAt: Date | null;
   208→  conversationId?: string; // DB conversation ID if synced
   209→  // Summary for context (loaded from DB, not full messages)
   210→  previousSummary?: string;
   211→  previousKeyFacts?: string[];
   212→  previousTopics?: string[];
   213→}
   214→
   215→/**
   216→ * Handoff suggestion from character routing.
   217→ */
   218→export interface HandoffSuggestion {
   219→  toCharacter: ActiveCharacter;
   220→  reason: string;
   221→  confidence: number;
   222→}
   223→
   224→/**
   225→ * Conversation flow mode.
   226→ */
   227→export type FlowMode = 'text' | 'voice' | 'idle';
   228→
   229→// ============================================================================
   230→// STORE
   231→// ============================================================================
   232→
   233→interface ConversationFlowState {
   234→  // Current state
   235→  mode: FlowMode;
   236→  isActive: boolean;
   237→  activeCharacter: ActiveCharacter | null;
   238→  messages: FlowMessage[]; // Current character's messages (displayed)
   239→  pendingHandoff: HandoffSuggestion | null;
   240→
   241→  // SEPARATE CONVERSATIONS PER CHARACTER (#33)
   242→  conversationsByCharacter: Record<string, CharacterConversation>;
   243→
   244→  // Session tracking
   245→  sessionId: string | null;
   246→  sessionStartedAt: Date | null;
   247→
   248→  // Character history (for back navigation)
   249→  characterHistory: Array<{ type: CharacterType; id: string; timestamp: Date }>;
   250→
   251→  // Session summary state
   252→  showRatingModal: boolean;
   253→  sessionSummary: {
   254→    topics: string[];
   255→    summary: string;
   256→    duration: number;
   257→  } | null;
   258→
   259→  // Actions
   260→  startConversation: (profile: ExtendedStudentProfile) => void;
   261→  endConversation: () => void;
   262→  endConversationWithSummary: (conversationId: string, userId: string) => Promise<void>;
   263→  setMode: (mode: FlowMode) => void;
   264→  setShowRatingModal: (show: boolean) => void;
   265→
   266→  // Message actions
   267→  addMessage: (message: Omit<FlowMessage, 'id' | 'timestamp'>) => Promise<void>;
   268→  clearMessages: () => void;
   269→
   270→  // Character routing
   271→  routeMessage: (message: string, profile: ExtendedStudentProfile) => RoutingResult;
   272→  switchToCharacter: (
   273→    character: MaestroFull | SupportTeacher | BuddyProfile,
   274→    type: CharacterType,
   275→    profile: ExtendedStudentProfile,
   276→    reason?: string
   277→  ) => void;
   278→  switchToCoach: (profile: ExtendedStudentProfile) => void;
   279→  switchToMaestro: (maestro: MaestroFull, profile: ExtendedStudentProfile) => void;
   280→  switchToBuddy: (profile: ExtendedStudentProfile) => void;
   281→  goBack: (profile: ExtendedStudentProfile) => boolean;
   282→
   283→  // Handoff management
   284→  suggestHandoff: (suggestion: HandoffSuggestion) => void;
   285→  acceptHandoff: (profile: ExtendedStudentProfile) => void;
   286→  dismissHandoff: () => void;
   287→
   288→  // Conversation history
   289→  getConversationForCharacter: (characterId: string) => CharacterConversation | null;
   290→  getAllConversations: () => CharacterConversation[];
   291→
   292→  // Contextual greetings
   293→  loadContextualGreeting: (
   294→    userId: string,
   295→    characterId: string,
   296→    studentName: string,
   297→    maestroName: string
   298→  ) => Promise<string | null>;
   299→
   300→  // Reset
   301→  reset: () => void;
   302→
   303→  // Persistence
   304→  loadFromServer: () => Promise<void>;
   305→}
   306→
   307→/**
   308→ * Creates an ActiveCharacter from character data.
   309→ */
   310→function createActiveCharacter(
   311→  character: MaestroFull | SupportTeacher | BuddyProfile,
   312→  type: CharacterType,
   313→  profile: ExtendedStudentProfile
   314→): ActiveCharacter {
   315→  let greeting: string;
   316→  let systemPrompt: string;
   317→  let voiceInstructions: string;
   318→
   319→  if (type === 'buddy') {
   320→    const buddy = character as BuddyProfile;
   321→    greeting = buddy.getGreeting(profile);
   322→    systemPrompt = buddy.getSystemPrompt(profile);
   323→    voiceInstructions = buddy.voiceInstructions;
   324→  } else if (type === 'coach') {
   325→    const coach = character as SupportTeacher;
   326→    greeting = coach.greeting;
   327→    systemPrompt = coach.systemPrompt;
   328→    voiceInstructions = coach.voiceInstructions;
   329→  } else {
   330→    const maestro = character as MaestroFull;
   331→    greeting = maestro.greeting;
   332→    systemPrompt = maestro.systemPrompt;
   333→    voiceInstructions = '';
   334→  }
   335→
   336→  return {
   337→    type,
   338→    id: character.id,
   339→    name: character.name,
   340→    character,
   341→    greeting,
   342→    systemPrompt,
   343→    color: character.color,
   344→    voice: 'voice' in character ? character.voice : 'alloy',
   345→    voiceInstructions,
   346→  };
   347→}
   348→
   349→/**
   350→ * Save current messages to character's conversation bucket.
   351→ */
   352→function saveCurrentConversation(
   353→  state: ConversationFlowState
   354→): Record<string, CharacterConversation> {
   355→  if (!state.activeCharacter || state.messages.length === 0) {
   356→    return state.conversationsByCharacter;
   357→  }
   358→
   359→  const characterId = state.activeCharacter.id;
   360→  const existingConvo = state.conversationsByCharacter[characterId];
   361→
   362→  return {
   363→    ...state.conversationsByCharacter,
   364→    [characterId]: {
   365→      characterId,
   366→      characterType: state.activeCharacter.type,
   367→      characterName: state.activeCharacter.name,
   368→      messages: state.messages,
   369→      lastMessageAt: new Date(),
   370→      conversationId: existingConvo?.conversationId,
   371→    },
   372→  };
   373→}
   374→
   375→/**
   376→ * Load messages for a character from their conversation bucket.
   377→ */
   378→function loadConversationMessages(
   379→  conversationsByCharacter: Record<string, CharacterConversation>,
   380→  characterId: string
   381→): FlowMessage[] {
   382→  const convo = conversationsByCharacter[characterId];
   383→  return convo?.messages || [];
   384→}
   385→
   386→export const useConversationFlowStore = create<ConversationFlowState>()(
   387→  (set, get) => ({
   388→      mode: 'idle',
   389→      isActive: false,
   390→      activeCharacter: null,
   391→      messages: [],
   392→      pendingHandoff: null,
   393→      conversationsByCharacter: {},
   394→      sessionId: null,
   395→      sessionStartedAt: null,
   396→      characterHistory: [],
   397→      showRatingModal: false,
   398→      sessionSummary: null,
   399→
   400→      startConversation: (profile) => {
   401→        const coach = getDefaultSupportTeacher();
   402→        const activeCharacter = createActiveCharacter(coach, 'coach', profile);
   403→
   404→        // Check if we have existing conversation with this coach
   405→        const state = get();
   406→        const existingMessages = loadConversationMessages(
   407→          state.conversationsByCharacter,
   408→          coach.id
   409→        );
   410→
   411→        // If no existing messages, start with greeting
   412→        const messages: FlowMessage[] =
   413→          existingMessages.length > 0
   414→            ? existingMessages
   415→            : [
   416→                {
   417→                  id: crypto.randomUUID(),
   418→                  role: 'assistant',
   419→                  content: activeCharacter.greeting,
   420→                  timestamp: new Date(),
   421→                  characterId: activeCharacter.id,
   422→                  characterType: 'coach',
   423→                },
   424→              ];
   425→
   426→        set({
   427→          isActive: true,
   428→          mode: 'text',
   429→          activeCharacter,
   430→          messages,
   431→          sessionId: crypto.randomUUID(),
   432→          sessionStartedAt: new Date(),
   433→          characterHistory: [{ type: 'coach', id: coach.id, timestamp: new Date() }],
   434→          pendingHandoff: null,
   435→        });
   436→      },
   437→
   438→      endConversation: () => {
   439→        // Save current conversation before ending
   440→        const state = get();
   441→        const updatedConversations = saveCurrentConversation(state);
   442→
   443→        // Stop inactivity monitoring
   444→        if (state.sessionId) {
   445→          inactivityMonitor.stopTracking(state.sessionId);
   446→        }
   447→
   448→        set({
   449→          isActive: false,
   450→          mode: 'idle',
   451→          activeCharacter: null,
   452→          messages: [],
   453→          pendingHandoff: null,
   454→          sessionId: null,
   455→          sessionStartedAt: null,
   456→          characterHistory: [],
   457→          conversationsByCharacter: updatedConversations,
   458→          showRatingModal: false,
   459→          sessionSummary: null,
   460→        });
   461→      },
   462→
   463→      endConversationWithSummary: async (conversationId: string, _userId: string) => {
   464→        const state = get();
   465→
   466→        // Stop inactivity monitoring
   467→        inactivityMonitor.stopTracking(conversationId);
   468→
   469→        // Calculate session duration
   470→        const duration = state.sessionStartedAt
   471→          ? Math.round((Date.now() - state.sessionStartedAt.getTime()) / 60000)
   472→          : 0;
   473→
   474→        try {
   475→          // Generate summary
   476→          const result = await generateSummary(conversationId);
   477→
   478→          if (result) {
   479→            set({
   480→              sessionSummary: {
   481→                topics: result.topics,
   482→                summary: result.summary,
   483→                duration,
   484→              },
   485→              showRatingModal: true,
   486→            });
   487→          }
   488→        } catch (error) {
   489→          console.error('Failed to generate summary:', error);
   490→        }
   491→
   492→        // Save conversation
   493→        const updatedConversations = saveCurrentConversation(state);
   494→
   495→        set({
   496→          isActive: false,
   497→          mode: 'idle',
   498→          conversationsByCharacter: updatedConversations,
   499→        });
   500→      },
   501→
   502→      setMode: (mode) => set({ mode }),
   503→
   504→      setShowRatingModal: (show: boolean) => set({ showRatingModal: show }),
   505→
   506→      addMessage: async (message) => {
   507→        const state = get();
   508→        const newMessage: FlowMessage = {
   509→          ...message,
   510→          id: crypto.randomUUID(),
   511→          timestamp: new Date(),
   512→          characterId: message.role === 'assistant' ? state.activeCharacter?.id : undefined,
   513→          characterType: message.role === 'assistant' ? state.activeCharacter?.type : undefined,
   514→        };
   515→
   516→        const newMessages = [...state.messages, newMessage];
   517→
   518→        // Also update the conversation bucket
   519→        const characterId = state.activeCharacter?.id;
   520→        let updatedConversations = state.conversationsByCharacter;
   521→        let conversationId = state.conversationsByCharacter[characterId || '']?.conversationId;
   522→
   523→        if (characterId && state.activeCharacter) {
   524→          // Create conversation in DB if not exists
   525→          if (!conversationId) {
   526→            conversationId = await createConversationInDB(
   527→              characterId,
   528→              state.activeCharacter.type,
   529→              state.activeCharacter.name
   530→            ) || undefined;
   531→          }
   532→
   533→          updatedConversations = {
   534→            ...state.conversationsByCharacter,
   535→            [characterId]: {
   536→              characterId,
   537→              characterType: state.activeCharacter.type,
   538→              characterName: state.activeCharacter.name,
   539→              messages: newMessages,
   540→              lastMessageAt: new Date(),
   541→              conversationId,
   542→            },
   543→          };
   544→
   545→          // Persist message to DB (fire and forget)
   546→          if (conversationId) {
   547→            saveMessageToDB(conversationId, newMessage.role, newMessage.content);
   548→          }
   549→        }
   550→
   551→        set({
   552→          messages: newMessages,
   553→          conversationsByCharacter: updatedConversations,
   554→        });
   555→      },
   556→
   557→      clearMessages: () => {
   558→        const state = get();
   559→        const characterId = state.activeCharacter?.id;
   560→
   561→        // Also clear from conversation bucket
   562→        if (characterId) {
   563→          const { [characterId]: _, ...rest } = state.conversationsByCharacter;
   564→          set({ messages: [], conversationsByCharacter: rest });
   565→        } else {
   566→          set({ messages: [] });
   567→        }
   568→      },
   569→
   570→      routeMessage: (message, profile) => {
   571→        const state = get();
   572→        return routeToCharacter({
   573→          message,
   574→          studentProfile: profile,
   575→          currentCharacter: state.activeCharacter
   576→            ? { type: state.activeCharacter.type, id: state.activeCharacter.id }
   577→            : undefined,
   578→          preferContinuity: true,
   579→        });
   580→      },
   581→
   582→      switchToCharacter: (character, type, profile, _reason) => {
   583→        const state = get();
   584→
   585→        // 1. Save current conversation to its bucket
   586→        const savedConversations = saveCurrentConversation(state);
   587→
   588→        // 2. Create new active character
   589→        const activeCharacter = createActiveCharacter(character, type, profile);
   590→
   591→        // 3. Load existing messages for new character (or start fresh)
   592→        let messages = loadConversationMessages(savedConversations, character.id);
   593→
   594→        if (messages.length === 0) {
   595→          // No existing conversation - add greeting
   596→          messages = [
   597→            {
   598→              id: crypto.randomUUID(),
   599→              role: 'assistant',
   600→              content: activeCharacter.greeting,
   601→              timestamp: new Date(),
   602→              characterId: activeCharacter.id,
   603→              characterType: type,
   604→            },
   605→          ];
   606→        }
   607→
   608→        // 4. Update history
   609→        const newHistory = [
   610→          ...state.characterHistory,
   611→          { type, id: character.id, timestamp: new Date() },
   612→        ];
   613→
   614→        set({
   615→          activeCharacter,
   616→          messages,
   617→          characterHistory: newHistory,
   618→          pendingHandoff: null,
   619→          conversationsByCharacter: savedConversations,
   620→        });
   621→      },
   622→
   623→      switchToCoach: (profile) => {
   624→        const coach = getDefaultSupportTeacher();
   625→        get().switchToCharacter(coach, 'coach', profile);
   626→      },
   627→
   628→      switchToMaestro: (maestro, profile) => {
   629→        get().switchToCharacter(maestro, 'maestro', profile);
   630→      },
   631→
   632→      switchToBuddy: (profile) => {
   633→        const buddy = getBuddyForStudent(profile);
   634→        get().switchToCharacter(buddy, 'buddy', profile);
   635→      },
   636→
   637→      goBack: (profile) => {
   638→        const state = get();
   639→        if (state.characterHistory.length <= 1) {
   640→          return false;
   641→        }
   642→
   643→        // Save current before going back
   644→        const savedConversations = saveCurrentConversation(state);
   645→
   646→        const newHistory = state.characterHistory.slice(0, -1);
   647→        const previous = newHistory[newHistory.length - 1];
   648→
   649→        let character: MaestroFull | SupportTeacher | BuddyProfile | undefined;
   650→
   651→        switch (previous.type) {
   652→          case 'maestro':
   653→            character = getMaestroById(previous.id);
   654→            break;
   655→          case 'coach':
   656→            character = getSupportTeacherById(previous.id as 'melissa' | 'roberto');
   657→            break;
   658→          case 'buddy':
   659→            character = getBuddyById(previous.id as BuddyId);
   660→            break;
   661→        }
   662→
   663→        if (!character) {
   664→          return false;
   665→        }
   666→
   667→        const activeCharacter = createActiveCharacter(character, previous.type, profile);
   668→
   669→        // Load that character's messages
   670→        const messages = loadConversationMessages(savedConversations, previous.id);
   671→
   672→        set({
   673→          activeCharacter,
   674→          messages: messages.length > 0 ? messages : [
   675→            {
   676→              id: crypto.randomUUID(),
   677→              role: 'assistant',
   678→              content: activeCharacter.greeting,
   679→              timestamp: new Date(),
   680→              characterId: activeCharacter.id,
   681→              characterType: previous.type,
   682→            },
   683→          ],
   684→          characterHistory: newHistory,
   685→          pendingHandoff: null,
   686→          conversationsByCharacter: savedConversations,
   687→        });
   688→
   689→        return true;
   690→      },
   691→
   692→      suggestHandoff: (suggestion) => {
   693→        set({ pendingHandoff: suggestion });
   694→      },
   695→
   696→      acceptHandoff: (profile) => {
   697→        const state = get();
   698→        if (!state.pendingHandoff) return;
   699→
   700→        const { toCharacter } = state.pendingHandoff;
   701→        get().switchToCharacter(toCharacter.character, toCharacter.type, profile);
   702→      },
   703→
   704→      dismissHandoff: () => {
   705→        set({ pendingHandoff: null });
   706→      },
   707→
   708→      getConversationForCharacter: (characterId) => {
   709→        const state = get();
   710→        return state.conversationsByCharacter[characterId] || null;
   711→      },
   712→
   713→      getAllConversations: () => {
   714→        const state = get();
   715→        return Object.values(state.conversationsByCharacter).sort((a, b) => {
   716→          const aTime = a.lastMessageAt?.getTime() || 0;
   717→          const bTime = b.lastMessageAt?.getTime() || 0;
   718→          return bTime - aTime; // Most recent first
   719→        });
   720→      },
   721→
   722→      loadContextualGreeting: async (
   723→        userId: string,
   724→        characterId: string,
   725→        studentName: string,
   726→        maestroName: string
   727→      ): Promise<string | null> => {
