   730→            userId,
   731→            characterId,
   732→            studentName,
   733→            maestroName
   734→          );
   735→          return result?.greeting || null;
   736→        } catch (error) {
   737→          console.error('Failed to load contextual greeting:', error);
   738→          return null;
   739→        }
   740→      },
   741→
   742→      reset: () => {
   743→        // Stop all inactivity monitoring
   744→        inactivityMonitor.stopAll();
   745→
   746→        set({
   747→          mode: 'idle',
   748→          isActive: false,
   749→          activeCharacter: null,
   750→          messages: [],
   751→          pendingHandoff: null,
   752→          conversationsByCharacter: {},
   753→          sessionId: null,
   754→          sessionStartedAt: null,
   755→          characterHistory: [],
   756→          showRatingModal: false,
   757→          sessionSummary: null,
   758→        });
   759→      },
   760→
   761→      loadFromServer: async () => {
   762→        try {
   763→          // Load summaries, not full messages
   764→          const summaries = await loadConversationSummariesFromDB();
   765→          if (summaries.length === 0) return;
