   768→          const conversationsByCharacter: Record<string, CharacterConversation> = {};
   769→
   770→          for (const conv of summaries) {
   771→            const characterId = conv.maestroId;
   772→
   773→            // Determine character type from ID prefix
   774→            let characterType: CharacterType = 'maestro';
   775→            let characterName = conv.title.replace('Conversazione con ', '');
   776→
   777→            if (characterId.startsWith('coach-')) {
   778→              characterType = 'coach';
   779→              // Extract coach name from ID (e.g., 'coach-melissa' -> 'melissa')
   780→              const coachName = characterId.replace('coach-', '') as CoachId;
   781→              const coach = getSupportTeacherById(coachName);
   782→              if (coach) characterName = coach.name;
   783→            } else if (characterId.startsWith('buddy-')) {
   784→              characterType = 'buddy';
   785→              const buddy = getBuddyById(characterId as BuddyId);
   786→              if (buddy) characterName = buddy.name;
   787→            } else {
   788→              const maestro = getMaestroById(characterId);
