     1→/**
     2→ * ConvergioEdu Conversation Flow Component
     3→ *
     4→ * The central conversation-first interface that:
     5→ * 1. Shows character selection with photos and introductions
     6→ * 2. Routes student messages to appropriate characters
     7→ * 3. Supports seamless handoffs between characters
     8→ * 4. Offers both text and voice modes for Coach and Buddy
     9→ *
    10→ * Part of I-01: Conversation-First Main Flow
    11→ * Related: #24 MirrorBuddy Issue, #33 Conversation UX, ManifestoEdu.md
    12→ */
    13→
    14→'use client';
    15→
    16→import { useState, useRef, useEffect, useCallback, useMemo } from 'react';
    17→import { motion, AnimatePresence, useReducedMotion } from 'framer-motion';
    18→import {
