    28→import { useSettingsStore } from '@/lib/stores/app-store';
    29→import { logger } from '@/lib/logger';
    30→import { useConversationFlowStore } from '@/lib/stores/conversation-flow-store';
    31→// Note: routeMessage from store is used instead of direct routeToCharacter
    32→import { analyzeHandoff } from '@/lib/ai/handoff-manager';
    33→import { useMethodProgressStore } from '@/lib/stores/method-progress-store';
    34→import type { ExtendedStudentProfile, Subject } from '@/types';
    35→// Tool integration - T-15
    36→import { ToolButtons } from './tool-buttons';
    37→import { ToolPanel } from '@/components/tools/tool-panel';
    38→import type { ToolType, ToolState } from '@/types/tools';
    39→
    40→// Map OpenAI function names to ToolType
    41→const FUNCTION_NAME_TO_TOOL_TYPE: Record<string, ToolType> = {
    42→  create_mindmap: 'mindmap',
    43→  create_quiz: 'quiz',
    44→  create_demo: 'demo',
    45→  web_search: 'search',
    46→  create_flashcards: 'flashcard',
    47→  create_diagram: 'diagram',
    48→  create_timeline: 'timeline',
    49→  create_summary: 'summary',
    50→  open_student_summary: 'summary',
    51→};
    52→// Sub-components
    53→import {
    54→  CharacterAvatar,
    55→  MessageBubble,
    56→  HandoffBanner,
    57→  ConversationHeader,
    58→  VoiceCallOverlay,
    59→  CHARACTER_AVATARS,
    60→} from './components';
    61→
    62→// Re-export CharacterCard for external use
    63→export { CharacterCard } from './components';
    64→
    65→// ============================================================================
    66→// MAIN COMPONENT
    67→// ============================================================================
    68→
    69→export function ConversationFlow() {
    70→  const [inputValue, setInputValue] = useState('');
    71→  const [isLoading, setIsLoading] = useState(false);
    72→  const [isMuted, setIsMuted] = useState(false);
    73→  const [isVoiceActive, setIsVoiceActive] = useState(false);
    74→  const [activeTool, setActiveTool] = useState<ToolState | null>(null);
    75→  const [isToolMinimized, setIsToolMinimized] = useState(false);
    76→  const [voiceSessionId, setVoiceSessionId] = useState<string | null>(null);
    77→  const messagesEndRef = useRef<HTMLDivElement>(null);
    78→  const inputRef = useRef<HTMLInputElement>(null);
    79→  const sessionStartTimeRef = useRef<number>(Date.now());
    80→  const _prefersReducedMotion = useReducedMotion(); // For future accessibility features
    81→
    82→  // Stores
    83→  const { studentProfile } = useSettingsStore();
    84→  const {
    85→    isActive,
    86→    mode,
    87→    activeCharacter,
    88→    messages,
    89→    pendingHandoff,
    90→    characterHistory,
    91→    sessionId,
    92→    startConversation,
    93→    endConversation: _endConversation, // Available for future explicit end
    94→    addMessage,
    95→    setMode,
    96→    switchToCoach,
    97→    switchToBuddy,
    98→    goBack,
    99→    acceptHandoff,
   100→    dismissHandoff,
   101→    suggestHandoff,
   102→    routeMessage,
   103→    switchToCharacter: _switchToCharacter, // Used internally via specific switch functions
   104→  } = useConversationFlowStore();
   105→
   106→  // Extended profile for routing - memoized to avoid unnecessary re-renders
   107→  const extendedProfile: ExtendedStudentProfile = useMemo(() => ({
   108→    ...studentProfile,
   109→    learningDifferences: studentProfile.learningDifferences || [],
   110→    preferredCoach: studentProfile.preferredCoach,
   111→    preferredBuddy: studentProfile.preferredBuddy,
   112→  }), [studentProfile]);
   113→
   114→  // Handle tool request from ToolButtons
   115→  const handleToolRequest = useCallback(async (toolType: ToolType) => {
   116→    if (!activeCharacter || isLoading) return;
   117→
   118→    // Create tool prompts based on type
   119→    const toolPrompts: Record<ToolType, string> = {
   120→      mindmap: 'Crea una mappa mentale su questo argomento',
   121→      quiz: 'Crea un quiz per verificare la mia comprensione',
   122→      flashcard: 'Crea delle flashcard per memorizzare',
   123→      demo: 'Crea una demo interattiva per visualizzare',
   124→      search: 'Cerca risorse educative su questo argomento',
   125→      webcam: 'Voglio scattare una foto',
   126→      diagram: 'Crea un diagramma',
   127→      timeline: 'Crea una linea del tempo',
   128→      summary: 'Crea un riassunto',
   129→      formula: 'Mostra la formula',
   130→      chart: 'Crea un grafico',
   131→      pdf: 'Analizza il PDF',
   132→      homework: 'Aiutami con i compiti',
   133→    };
   134→
   135→    const toolPrompt = toolPrompts[toolType] || `Crea ${toolType}`;
   136→    setInputValue('');
   137→    setIsLoading(true);
   138→
   139→    addMessage({ role: 'user', content: toolPrompt });
   140→
   141→    // Create initial tool state
   142→    const newTool: ToolState = {
   143→      id: `tool-${Date.now()}`,
   144→      type: toolType,
   145→      status: 'initializing',
   146→      progress: 0,
   147→      content: null,
   148→      createdAt: new Date(),
   149→    };
   150→    setActiveTool(newTool);
   151→
   152→    try {
   153→      const response = await fetch('/api/chat', {
   154→        method: 'POST',
   155→        headers: { 'Content-Type': 'application/json' },
   156→        body: JSON.stringify({
   157→          messages: [
   158→            { role: 'system', content: activeCharacter.systemPrompt },
   159→            ...messages
   160→              .filter((m) => m.role !== 'system')
   161→              .map((m) => ({ role: m.role, content: m.content })),
   162→            { role: 'user', content: toolPrompt },
   163→          ],
   164→          maestroId: activeCharacter.id,
   165→          requestedTool: toolType,
   166→          enableMemory: true, // ADR 0021: Enable conversational memory injection
   167→        }),
   168→      });
   169→
   170→      if (!response.ok) throw new Error('Failed to get response');
   171→      const data = await response.json();
   172→
   173→      const assistantContent = data.content || data.message || '';
   174→      addMessage({ role: 'assistant', content: assistantContent });
   175→
   176→      // Update tool state based on response
   177→      if (data.toolCalls?.length > 0) {
   178→        const toolCall = data.toolCalls[0];
   179→        // Map function name (create_quiz) to tool type (quiz)
   180→        const mappedToolType = FUNCTION_NAME_TO_TOOL_TYPE[toolCall.type] || toolType;
   181→        // Extract actual data from result object
   182→        const toolContent = toolCall.result?.data || toolCall.result || toolCall.arguments;
   183→        setActiveTool({
   184→          ...newTool,
   185→          type: mappedToolType,
   186→          status: 'completed',
   187→          progress: 1,
   188→          content: toolContent,
   189→        });
   190→      } else {
   191→        // No tool was created, clear the state
   192→        setActiveTool(null);
   193→      }
   194→    } catch (error) {
   195→      logger.error('Tool request error', { error });
   196→      addMessage({
   197→        role: 'assistant',
   198→        content: 'Mi dispiace, non sono riuscito a creare lo strumento. Riprova?',
   199→      });
   200→      setActiveTool({
   201→        ...newTool,
   202→        status: 'error',
   203→        error: 'Errore nella creazione dello strumento',
   204→      });
   205→    } finally {
   206→      setIsLoading(false);
   207→    }
   208→  }, [activeCharacter, isLoading, messages, addMessage]);
   209→
   210→  // Auto-scroll to bottom
   211→  useEffect(() => {
   212→    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
   213→  }, [messages]);
   214→
   215→  // Focus input when conversation starts
   216→  useEffect(() => {
   217→    if (isActive && mode === 'text') {
   218→      inputRef.current?.focus();
   219→    }
   220→  }, [isActive, mode]);
   221→
   222→  // Start conversation on mount if not active
   223→  useEffect(() => {
   224→    if (!isActive) {
   225→      startConversation(extendedProfile);
   226→    }
   227→  }, [isActive, startConversation, extendedProfile]);
   228→
   229→  // SSE listener for real-time tool events (Phase 4: Fullscreen Layout)
   230→  useEffect(() => {
   231→    if (!sessionId) return;
   232→
   233→    const eventSource = new EventSource(`/api/tools/sse?sessionId=${sessionId}`);
   234→
   235→    eventSource.onmessage = (event) => {
   236→      try {
   237→        const data = JSON.parse(event.data);
   238→
   239→        switch (data.type) {
   240→          case 'connected':
   241→            logger.debug('SSE connected', { sessionId, clientId: data.clientId });
   242→            break;
   243→
   244→          case 'tool:created':
   245→            // Tool creation started - show in panel
   246→            setActiveTool({
   247→              id: data.toolId,
   248→              type: data.toolType,
   249→              status: 'initializing',
   250→              progress: 0,
   251→              content: data.data,
   252→              createdAt: new Date(),
   253→            });
   254→            break;
   255→
   256→          case 'tool:update':
   257→            // Incremental update during building
   258→            setActiveTool((prev) => {
   259→              if (!prev || prev.id !== data.toolId) return prev;
   260→              return {
   261→                ...prev,
   262→                status: 'building',
   263→                progress: data.progress ?? prev.progress,
   264→                content: data.data ?? prev.content,
   265→              };
   266→            });
   267→            break;
   268→
   269→          case 'tool:complete':
   270→            // Tool finished building
   271→            setActiveTool((prev) => {
   272→              if (!prev || prev.id !== data.toolId) return prev;
   273→              return {
   274→                ...prev,
   275→                status: 'completed',
   276→                progress: 1,
   277→                content: data.data ?? prev.content,
   278→              };
   279→            });
   280→            break;
   281→
   282→          case 'tool:error':
   283→            // Tool build failed
   284→            setActiveTool((prev) => {
   285→              if (!prev || prev.id !== data.toolId) return prev;
   286→              return {
   287→                ...prev,
   288→                status: 'error',
   289→                error: data.error || 'Errore durante la creazione',
   290→              };
   291→            });
   292→            break;
   293→
   294→          case 'heartbeat':
   295→            // Keep-alive, no action needed
   296→            break;
   297→
   298→          default:
   299→            logger.debug('Unknown SSE event type', { type: data.type });
   300→        }
   301→      } catch (error) {
   302→        logger.error('SSE message parse error', { error: String(error) });
   303→      }
   304→    };
   305→
   306→    eventSource.onerror = (error) => {
   307→      logger.error('SSE connection error', { error: String(error) });
   308→      // EventSource will automatically try to reconnect
   309→    };
   310→
   311→    return () => {
   312→      eventSource.close();
   313→      logger.debug('SSE connection closed', { sessionId });
   314→    };
   315→  }, [sessionId]);
   316→
   317→  /**
   318→   * Handle sending a message.
   319→   */
   320→  const handleSend = useCallback(async () => {
   321→    if (!inputValue.trim() || isLoading || !activeCharacter) return;
   322→
   323→    const userMessage = inputValue.trim();
   324→    setInputValue('');
   325→    setIsLoading(true);
   326→
   327→    // Add user message
   328→    addMessage({ role: 'user', content: userMessage });
   329→
   330→    try {
   331→      // Route the message to determine if we need to switch characters
   332→      const routingResult = routeMessage(userMessage, extendedProfile);
   333→
   334→      // Track method progress based on intent (autonomy tracking - Issue #28)
   335→      const methodProgressStore = useMethodProgressStore.getState();
   336→
   337→      // Map main Subject type (English) to method-progress Subject type (Italian)
   338→      const mapToMethodSubject = (subject?: Subject): import('@/lib/method-progress/types').Subject | undefined => {
   339→        if (!subject) return undefined;
   340→        const subjectMap: Record<string, import('@/lib/method-progress/types').Subject> = {
   341→          mathematics: 'matematica',
   342→          physics: 'scienze',
   343→          chemistry: 'scienze',
   344→          biology: 'scienze',
   345→          history: 'storia',
   346→          geography: 'geografia',
   347→          italian: 'italiano',
   348→          english: 'inglese',
   349→          art: 'arte',
   350→          music: 'musica',
   351→        };
   352→        return subjectMap[subject] ?? 'other';
   353→      };
   354→
   355→      if (routingResult.intent.type === 'method_help' ||
   356→          routingResult.intent.type === 'emotional_support') {
   357→        // Student is seeking help - track as help request
   358→        const timeElapsed = Math.round((Date.now() - sessionStartTimeRef.current) / 1000);
   359→        methodProgressStore.recordHelpRequest(
   360→          routingResult.reason,
   361→          timeElapsed,
   362→          mapToMethodSubject(routingResult.intent.subject)
   363→        );
   364→      } else if (routingResult.intent.type === 'academic_help' &&
   365→                 activeCharacter?.type === 'maestro') {
   366→        // Student is working independently with a maestro
   367→        // Only track as "solved alone" if they've been working for a while
   368→        if (messages.length > 4) {
   369→          methodProgressStore.recordProblemSolvedAlone(
   370→            userMessage.slice(0, 100),
   371→            mapToMethodSubject(routingResult.intent.subject)
   372→          );
   373→        }
   374→      }
   375→
   376→      // Check if we should suggest a handoff
   377→      if (
   378→        routingResult.characterType !== activeCharacter.type &&
   379→        routingResult.intent.confidence >= 0.7
   380→      ) {
   381→        // High confidence different character needed - suggest handoff
   382→        const { getMaestroById: _getMaestroById } = await import('@/data/maestri');
   383→        const { getSupportTeacherById } = await import('@/data/support-teachers');
   384→        const { getBuddyById } = await import('@/data/buddy-profiles');
   385→
   386→        let targetCharacter;
   387→        switch (routingResult.characterType) {
   388→          case 'maestro':
   389→            targetCharacter = routingResult.character;
   390→            break;
   391→          case 'coach':
   392→            targetCharacter =
   393→              getSupportTeacherById(extendedProfile.preferredCoach || 'melissa') ||
   394→              routingResult.character;
   395→            break;
   396→          case 'buddy':
   397→            targetCharacter =
   398→              getBuddyById(extendedProfile.preferredBuddy || 'mario') ||
   399→              routingResult.character;
   400→            break;
   401→        }
   402→
   403→        if (targetCharacter && targetCharacter.id !== activeCharacter.id) {
   404→          // Create active character for handoff
   405→          const handoffCharacter = {
   406→            type: routingResult.characterType,
   407→            id: targetCharacter.id,
   408→            name: targetCharacter.name,
   409→            character: targetCharacter,
   410→            greeting:
   411→              routingResult.characterType === 'buddy' && 'getGreeting' in targetCharacter
   412→                ? (targetCharacter as { getGreeting: (p: ExtendedStudentProfile) => string }).getGreeting(extendedProfile)
   413→                : 'greeting' in targetCharacter ? String(targetCharacter.greeting) : '',
   414→            systemPrompt:
   415→              routingResult.characterType === 'buddy' && 'getSystemPrompt' in targetCharacter
   416→                ? (targetCharacter as { getSystemPrompt: (p: ExtendedStudentProfile) => string }).getSystemPrompt(extendedProfile)
   417→                : 'systemPrompt' in targetCharacter ? String(targetCharacter.systemPrompt) : '',
   418→            color: targetCharacter.color,
   419→            voice: 'voice' in targetCharacter ? targetCharacter.voice : 'alloy',
   420→            voiceInstructions: 'voiceInstructions' in targetCharacter ? targetCharacter.voiceInstructions : '',
   421→          };
   422→
   423→          // Suggest handoff instead of auto-switching
   424→          suggestHandoff({
   425→            toCharacter: handoffCharacter,
   426→            reason: routingResult.reason,
   427→            confidence: routingResult.intent.confidence,
   428→          });
   429→        }
   430→      }
   431→
   432→      // Send to AI for response with memory context (ADR 0021)
   433→      const response = await fetch('/api/chat', {
   434→        method: 'POST',
   435→        headers: { 'Content-Type': 'application/json' },
   436→        body: JSON.stringify({
   437→          messages: [
   438→            { role: 'system', content: activeCharacter.systemPrompt },
   439→            ...messages
   440→              .filter((m) => m.role !== 'system')
   441→              .map((m) => ({
   442→                role: m.role,
   443→                content: m.content,
   444→              })),
   445→            { role: 'user', content: userMessage },
   446→          ],
   447→          maestroId: activeCharacter.id,
   448→          enableMemory: true, // ADR 0021: Enable conversational memory injection
   449→        }),
   450→      });
   451→
   452→      if (!response.ok) {
   453→        throw new Error('Failed to get response');
   454→      }
   455→
   456→      const data = await response.json();
   457→      const assistantContent = data.content || data.message || '';
   458→      addMessage({ role: 'assistant', content: assistantContent });
   459→
   460→      // Also check AI response for handoff signals (reactive detection)
   461→      if (!pendingHandoff) {
   462→        const handoffAnalysis = analyzeHandoff({
   463→          message: userMessage,
   464→          aiResponse: assistantContent,
   465→          activeCharacter,
   466→          studentProfile: extendedProfile,
   467→          recentMessages: messages.slice(-5).map((m) => ({
   468→            role: m.role === 'system' ? 'assistant' : (m.role as 'user' | 'assistant'),
   469→            content: m.content,
   470→          })),
   471→        });
   472→
   473→        if (handoffAnalysis.shouldHandoff && handoffAnalysis.suggestion && handoffAnalysis.confidence > 0.7) {
   474→          suggestHandoff(handoffAnalysis.suggestion);
   475→        }
   476→      }
   477→    } catch (error) {
   478→      logger.error('Chat error', { error });
   479→      addMessage({
   480→        role: 'assistant',
   481→        content: 'Mi dispiace, ho avuto un problema. Puoi riprovare?',
   482→      });
   483→    } finally {
   484→      setIsLoading(false);
   485→    }
   486→  }, [
   487→    inputValue,
   488→    isLoading,
   489→    activeCharacter,
   490→    addMessage,
   491→    messages,
   492→    extendedProfile,
   493→    routeMessage,
   494→    suggestHandoff,
   495→    pendingHandoff,
   496→  ]);
   497→
   498→  /**
   499→   * Handle key press in input.
   500→   */
   501→  const handleKeyPress = (e: React.KeyboardEvent) => {
   502→    if (e.key === 'Enter' && !e.shiftKey) {
   503→      e.preventDefault();
   504→      handleSend();
   505→    }
   506→  };
   507→
   508→  /**
   509→   * Handle voice mode toggle (for input area).
   510→   */
   511→  const handleVoiceToggle = () => {
   512→    if (mode === 'voice') {
   513→      setMode('text');
   514→    } else {
   515→      setMode('voice');
   516→    }
   517→  };
   518→
   519→  /**
   520→   * Handle voice call (full voice conversation).
   521→   */
   522→  const handleVoiceCall = useCallback(() => {
   523→    if (isVoiceActive) {
   524→      // End voice call
   525→      setIsVoiceActive(false);
   526→      setMode('text');
   527→    } else {
   528→      // Start voice call
   529→      setIsVoiceActive(true);
   530→      setMode('voice');
   531→      // Voice session will be started by VoiceCallOverlay
   532→      // This is a placeholder - Issue #34 tracks voice WebSocket issues
   533→    }
   534→  }, [isVoiceActive, setMode]);
   535→
   536→  /**
   537→   * Handle accepting handoff.
   538→   */
   539→  const handleAcceptHandoff = () => {
   540→    acceptHandoff(extendedProfile);
   541→  };
   542→
   543→  /**
   544→   * Handle manual character switches.
   545→   */
   546→  const handleSwitchToCoach = () => switchToCoach(extendedProfile);
   547→  const handleSwitchToBuddy = () => switchToBuddy(extendedProfile);
   548→  const handleGoBack = () => goBack(extendedProfile);
   549→
   550→  // Render idle state (shouldn't happen with auto-start)
   551→  if (!isActive || !activeCharacter) {
   552→    return (
   553→      <div className="flex items-center justify-center h-full">
   554→        <Button onClick={() => startConversation(extendedProfile)}>
   555→          Inizia una conversazione
   556→        </Button>
   557→      </div>
   558→    );
   559→  }
   560→
   561→  // Video conference layout when tool is active (Issue #36)
   562→  const hasActiveTool = activeTool && activeTool.status !== 'error';
   563→
   564→  return (
   565→    <div className="relative flex flex-col h-[calc(100vh-200px)] max-h-[700px] bg-white dark:bg-slate-900 rounded-2xl shadow-xl overflow-hidden">
   566→      {/* Voice call overlay */}
   567→      <AnimatePresence>
   568→        {isVoiceActive && activeCharacter && (
   569→          <VoiceCallOverlay
   570→            character={activeCharacter}
   571→            onEnd={handleVoiceCall}
   572→            onSessionIdChange={setVoiceSessionId}
   573→          />
   574→        )}
   575→      </AnimatePresence>
   576→
   577→      {/* Header with character info and voice call button - 10% */}
   578→      <ConversationHeader
   579→        currentCharacter={activeCharacter}
   580→        onSwitchToCoach={handleSwitchToCoach}
   581→        onSwitchToBuddy={handleSwitchToBuddy}
   582→        onGoBack={handleGoBack}
   583→        canGoBack={characterHistory.length > 1}
   584→        isVoiceActive={isVoiceActive}
   585→        onVoiceCall={handleVoiceCall}
   586→      />
   587→
   588→      {/* Handoff suggestion */}
   589→      <AnimatePresence>
   590→        {pendingHandoff && (
   591→          <HandoffBanner
   592→            suggestion={pendingHandoff}
   593→            onAccept={handleAcceptHandoff}
   594→            onDismiss={dismissHandoff}
   595→          />
   596→        )}
   597→      </AnimatePresence>
   598→
   599→      {/* Main content area - switches between chat-first and tool-first layouts */}
   600→      {hasActiveTool ? (
   601→        /* VIDEO CONFERENCE LAYOUT: Tool takes center stage (Issue #36) */
   602→        <div className="flex-1 flex flex-col overflow-hidden">
   603→          {/* Tool panel - 70% of remaining space */}
   604→          <div className="flex-[7] overflow-auto border-b border-slate-200 dark:border-slate-700">
   605→            <ToolPanel
   606→              tool={activeTool}
   607→              maestro={activeCharacter ? {
   608→                name: activeCharacter.name,
   609→                avatar: CHARACTER_AVATARS[activeCharacter.id] || '/avatars/default.jpg',
   610→                color: activeCharacter.color,
   611→              } : null}
   612→              onClose={() => setActiveTool(null)}
   613→              isMinimized={isToolMinimized}
   614→              onToggleMinimize={() => setIsToolMinimized(!isToolMinimized)}
   615→              embedded={true}
   616→              sessionId={voiceSessionId}
   617→            />
   618→          </div>
   619→
   620→          {/* Mini chat - 15% of remaining space */}
   621→          <div
   622→            className="flex-[1.5] overflow-y-auto p-2 bg-slate-50 dark:bg-slate-800/50"
   623→            role="log"
   624→            aria-live="polite"
   625→            aria-label="Messaggi recenti"
   626→          >
   627→            {/* Show only last 3 messages in mini view */}
   628→            {messages.slice(-3).map((message) => (
   629→              <div
   630→                key={message.id}
   631→                className={cn(
   632→                  'text-xs py-1 px-2 rounded mb-1',
   633→                  message.role === 'user'
   634→                    ? 'bg-accent-themed/10 text-right'
   635→                    : 'bg-slate-200 dark:bg-slate-700'
   636→                )}
   637→              >
   638→                <span className="font-medium">
   639→                  {message.role === 'user' ? 'Tu' : activeCharacter?.name}:
   640→                </span>{' '}
   641→                {message.content.substring(0, 80)}
   642→                {message.content.length > 80 && '...'}
   643→              </div>
   644→            ))}
   645→            {isLoading && (
   646→              <div className="text-xs py-1 px-2 flex items-center gap-1">
   647→                <Loader2 className="w-3 h-3 animate-spin" />
   648→                <span>{activeCharacter?.name} sta pensando...</span>
   649→              </div>
   650→            )}
   651→          </div>
   652→        </div>
   653→      ) : (
   654→        /* NORMAL LAYOUT: Chat takes full space */
   655→        <div
   656→          className="flex-1 overflow-y-auto p-4"
   657→          role="log"
   658→          aria-live="polite"
   659→          aria-label="Messaggi della conversazione"
   660→        >
   661→          {messages.map((message) => (
   662→            <MessageBubble
   663→              key={message.id}
   664→              message={message}
   665→              activeCharacter={
   666→                message.role === 'assistant' ? activeCharacter : null
   667→              }
   668→            />
   669→          ))}
   670→          {isLoading && (
   671→            <motion.div
   672→              initial={{ opacity: 0 }}
   673→              animate={{ opacity: 1 }}
   674→              className="flex gap-3 mb-4"
   675→            >
   676→              <CharacterAvatar character={activeCharacter} size="sm" />
   677→              <div className="px-4 py-3 bg-slate-100 dark:bg-slate-800 rounded-2xl rounded-bl-md">
   678→                <Loader2 className="w-5 h-5 animate-spin text-slate-500" />
   679→              </div>
   680→            </motion.div>
   681→          )}
   682→          <div ref={messagesEndRef} />
   683→        </div>
   684→      )}
   685→
   686→      {/* Input area - 5% */}
   687→      <div className="p-4 border-t border-slate-200 dark:border-slate-700">
   688→        <div className="flex items-center gap-2">
   689→          {/* Tool buttons - quick access to educational tools */}
   690→          <ToolButtons
   691→            onToolRequest={handleToolRequest}
   692→            disabled={isLoading}
   693→            activeToolId={activeTool?.id}
   694→          />
   695→          <input
   696→            ref={inputRef}
   697→            type="text"
   698→            value={inputValue}
   699→            onChange={(e) => setInputValue(e.target.value)}
   700→            onKeyDown={handleKeyPress}
   701→            placeholder={`Scrivi a ${activeCharacter.name}...`}
   702→            aria-label={`Scrivi un messaggio a ${activeCharacter.name}`}
   703→            className="flex-1 px-4 py-3 bg-slate-100 dark:bg-slate-800 rounded-xl border-0 focus:ring-2 focus:ring-accent-themed outline-none text-slate-900 dark:text-white placeholder:text-slate-500"
   704→            disabled={isLoading}
   705→          />
   706→          <Button
   707→            variant="ghost"
   708→            size="icon"
   709→            onClick={() => setIsMuted(!isMuted)}
   710→            aria-label={isMuted ? 'Attiva audio' : 'Disattiva audio'}
   711→            aria-pressed={isMuted}
   712→          >
   713→            {isMuted ? (
   714→              <VolumeX className="w-5 h-5" />
   715→            ) : (
   716→              <Volume2 className="w-5 h-5" />
   717→            )}
   718→          </Button>
   719→          <Button
   720→            variant="ghost"
   721→            size="icon"
   722→            onClick={handleVoiceToggle}
   723→            aria-label={mode === 'voice' ? 'Passa al testo' : 'Passa alla voce'}
   724→            aria-pressed={mode === 'voice'}
   725→            className={cn(mode === 'voice' && 'bg-red-100 text-red-600')}
   726→          >
   727→            {mode === 'voice' ? (
   728→              <MicOff className="w-5 h-5" />
   729→            ) : (
   730→              <Mic className="w-5 h-5" />
   731→            )}
   732→          </Button>
   733→          <Button
   734→            size="icon"
   735→            onClick={handleSend}
   736→            disabled={!inputValue.trim() || isLoading}
   737→            aria-label="Invia messaggio"
   738→            className="bg-accent-themed hover:bg-accent-themed/90"
   739→          >
   740→            <Send className="w-5 h-5" aria-hidden="true" />
   741→          </Button>
   742→        </div>
   743→      </div>
   744→    </div>
   745→  );
   746→}
