   161→      updateStudentProfile: (profile) =>
   162→        set((state) => ({
   163→          studentProfile: { ...state.studentProfile, ...profile },
   164→          pendingSync: true,
   165→        })),
   166→      updateAppearance: (appearance) =>
   167→        set((state) => ({
   168→          appearance: { ...state.appearance, ...appearance },
   169→          pendingSync: true,
   170→        })),
   171→      setPreferredProvider: (preferredProvider) =>
   172→        set({ preferredProvider, pendingSync: true }),
   173→      setPreferredMicrophone: (preferredMicrophoneId) =>
   174→        set({ preferredMicrophoneId, pendingSync: true }),
   175→      setPreferredOutput: (preferredOutputId) =>
   176→        set({ preferredOutputId, pendingSync: true }),
   177→      setPreferredCamera: (preferredCameraId) =>
   178→        set({ preferredCameraId, pendingSync: true }),
   179→      // Voice settings setters with validation
   180→      setVoiceVadThreshold: (threshold) =>
   181→        set({ voiceVadThreshold: Math.max(0.3, Math.min(0.7, threshold)), pendingSync: true }),
   182→      setVoiceSilenceDuration: (duration) =>
