   186→
   187→      syncToServer: async () => {
   188→        const state = get();
   189→        if (!state.pendingSync) return;
   190→
   191→        try {
   192→          // Sync settings - #88: Added totalSpent to persist budget tracking
   193→          await fetch('/api/user/settings', {
   194→            method: 'PUT',
   195→            headers: { 'Content-Type': 'application/json' },
