   348→
   349→const XP_PER_LEVEL = [
   350→  0, 100, 250, 500, 1000, 2000, 4000, 8000, 16000, 32000, 64000,
   351→];
   352→
   353→export const useProgressStore = create<ProgressState>()(
   354→  (set, get) => ({
   355→      xp: 0,
   356→      level: 1,
   357→      streak: { current: 0, longest: 0 },
   358→      masteries: [],
   359→      achievements: [],
   360→      totalStudyMinutes: 0,
   361→      sessionsThisWeek: 0,
   362→      questionsAsked: 0,
   363→      currentSession: null,
   364→      sessionHistory: [],
   365→      lastSyncedAt: null,
   366→      pendingSync: false,
   367→
   368→      addXP: (amount) =>
   369→        set((state) => {
   370→          const newXP = state.xp + amount;
   371→          let newLevel = state.level;
   372→          while (
   373→            newLevel < XP_PER_LEVEL.length - 1 &&
   374→            newXP >= XP_PER_LEVEL[newLevel]
   375→          ) {
   376→            newLevel++;
   377→          }
   378→          // Trigger level up notification if level increased
   379→          if (newLevel > state.level) {
   380→            const levelTitles: Record<number, string> = {
   381→              1: 'Principiante',
   382→              2: 'Apprendista',
   383→              3: 'Studente',
   384→              4: 'Studioso',
   385→              5: 'Esperto',
   386→              6: 'Professore',
   387→              7: 'Gran Professore',
   388→              8: 'Saggio',
   389→              9: 'Illuminato',
   390→              10: 'Leggenda',
   391→            };
   392→            onLevelUp(newLevel, levelTitles[newLevel] || `Livello ${newLevel}`);
   393→          }
   394→          // Update current session XP
   395→          const updatedSession = state.currentSession
   396→            ? { ...state.currentSession, xpEarned: state.currentSession.xpEarned + amount }
   397→            : null;
   398→          return { xp: newXP, level: newLevel, currentSession: updatedSession, pendingSync: true };
   399→        }),
   400→
   401→      updateStreak: () =>
   402→        set((state) => {
   403→          const today = new Date().toDateString();
   404→          const lastStudy = state.streak.lastStudyDate;
   405→          const yesterday = new Date(Date.now() - 86400000).toDateString();
   406→
   407→          let newCurrent = state.streak.current;
   408→          if (!lastStudy || new Date(lastStudy).toDateString() !== today) {
   409→            if (lastStudy && new Date(lastStudy).toDateString() === yesterday) {
   410→              newCurrent++;
   411→            } else if (!lastStudy || new Date(lastStudy).toDateString() !== yesterday) {
   412→              newCurrent = 1;
   413→            }
   414→          }
   415→
   416→          // Trigger streak milestone notification if applicable
   417→          if (newCurrent > state.streak.current) {
   418→            onStreakMilestone(newCurrent);
   419→          }
   420→
   421→          return {
   422→            streak: {
   423→              current: newCurrent,
   424→              longest: Math.max(state.streak.longest, newCurrent),
   425→              lastStudyDate: new Date(),
   426→            },
   427→            pendingSync: true,
   428→          };
   429→        }),
   430→
   431→      updateMastery: (subjectMastery) =>
   432→        set((state) => {
   433→          const existing = state.masteries.findIndex(
   434→            (m) => m.subject === subjectMastery.subject
   435→          );
   436→          if (existing >= 0) {
   437→            const newMasteries = [...state.masteries];
   438→            newMasteries[existing] = subjectMastery;
   439→            return { masteries: newMasteries, pendingSync: true };
   440→          }
   441→          return { masteries: [...state.masteries, subjectMastery], pendingSync: true };
   442→        }),
   443→
   444→      unlockAchievement: (achievementId) =>
   445→        set((state) => {
   446→          const achievement = state.achievements.find(
   447→            (a) => a.id === achievementId
   448→          );
   449→          if (achievement && !achievement.unlockedAt) {
   450→            // Trigger achievement notification
   451→            onAchievement(achievement.name, achievement.description);
   452→            return {
   453→              achievements: state.achievements.map((a) =>
   454→                a.id === achievementId ? { ...a, unlockedAt: new Date() } : a
   455→              ),
   456→              pendingSync: true,
   457→            };
   458→          }
   459→          return state;
   460→        }),
   461→
   462→      addStudyMinutes: (minutes) =>
   463→        set((state) => ({
   464→          totalStudyMinutes: state.totalStudyMinutes + minutes,
   465→          pendingSync: true,
   466→        })),
   467→
   468→      incrementQuestions: () =>
   469→        set((state) => {
   470→          const updatedSession = state.currentSession
   471→            ? { ...state.currentSession, questionsAsked: state.currentSession.questionsAsked + 1 }
   472→            : null;
   473→          return {
   474→            questionsAsked: state.questionsAsked + 1,
   475→            currentSession: updatedSession,
   476→            pendingSync: true,
   477→          };
   478→        }),
   479→
   480→      startSession: (maestroId, subject) =>
   481→        set((state) => {
   482→          // End any existing session first
   483→          if (state.currentSession) {
   484→            const endedSession = {
   485→              ...state.currentSession,
   486→              endedAt: new Date(),
   487→              durationMinutes: Math.round(
   488→                (Date.now() - new Date(state.currentSession.startedAt).getTime()) / 60000
   489→              ),
   490→            };
   491→            return {
   492→              currentSession: {
   493→                id: crypto.randomUUID(),
   494→                maestroId,
   495→                subject,
   496→                startedAt: new Date(),
   497→                questionsAsked: 0,
   498→                xpEarned: 0,
   499→              },
   500→              sessionHistory: [endedSession, ...state.sessionHistory].slice(0, 100),
   501→              pendingSync: true,
   502→            };
   503→          }
   504→          return {
   505→            currentSession: {
   506→              id: crypto.randomUUID(),
   507→              maestroId,
   508→              subject,
   509→              startedAt: new Date(),
   510→              questionsAsked: 0,
   511→              xpEarned: 0,
   512→            },
   513→            pendingSync: true,
   514→          };
   515→        }),
   516→
   517→      endSession: (grade) =>
   518→        set((state) => {
   519→          if (!state.currentSession) return state;
   520→
   521→          const durationMinutes = Math.round(
   522→            (Date.now() - new Date(state.currentSession.startedAt).getTime()) / 60000
   523→          );
   524→          const endedSession = {
   525→            ...state.currentSession,
   526→            endedAt: new Date(),
   527→            durationMinutes,
   528→            grade: grade || state.currentSession.grade,
   529→          };
   530→
   531→          // Calculate week sessions
   532→          const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
   533→          const recentSessions = [endedSession, ...state.sessionHistory].filter(
   534→            (s) => new Date(s.startedAt) > weekAgo
   535→          );
   536→
   537→          return {
   538→            currentSession: null,
   539→            sessionHistory: [endedSession, ...state.sessionHistory].slice(0, 100),
   540→            totalStudyMinutes: state.totalStudyMinutes + durationMinutes,
   541→            sessionsThisWeek: recentSessions.length,
   542→            pendingSync: true,
   543→          };
   544→        }),
   545→
   546→      gradeCurrentSession: (grade) =>
   547→        set((state) => {
   548→          if (!state.currentSession) return state;
   549→          return {
   550→            currentSession: { ...state.currentSession, grade },
   551→            pendingSync: true,
   552→          };
   553→        }),
   554→
   555→      syncToServer: async () => {
   556→        const state = get();
   557→        if (!state.pendingSync) return;
   558→
   559→        try {
   560→          // Sync main progress
   561→          await fetch('/api/progress', {
   562→            method: 'PUT',
   563→            headers: { 'Content-Type': 'application/json' },
   564→            body: JSON.stringify({
   565→              xp: state.xp,
   566→              level: state.level,
   567→              streak: state.streak,
   568→              totalStudyMinutes: state.totalStudyMinutes,
   569→              questionsAsked: state.questionsAsked,
   570→              masteries: state.masteries,
   571→              achievements: state.achievements,
   572→            }),
   573→          });
   574→
   575→          // Sync recent sessions
   576→          const unsyncedSessions = state.sessionHistory.filter(
   577→            (s) => s.endedAt && !s.id.startsWith('synced-')
   578→          ).slice(0, 10);
   579→
   580→          for (const session of unsyncedSessions) {
   581→            await fetch('/api/progress/sessions', {
   582→              method: 'POST',
   583→              headers: { 'Content-Type': 'application/json' },
   584→              body: JSON.stringify(session),
   585→            });
   586→          }
   587→
   588→          set({ lastSyncedAt: new Date(), pendingSync: false });
   589→        } catch (error) {
   590→          logger.error('Progress sync failed', { error: String(error) });
   591→        }
   592→      },
   593→
   594→      loadFromServer: async () => {
   595→        try {
   596→          const [progressRes, sessionsRes] = await Promise.all([
   597→            fetch('/api/progress'),
   598→            fetch('/api/progress/sessions?limit=20'),
   599→          ]);
   600→
   601→          if (progressRes.ok) {
   602→            const data = await progressRes.json();
   603→            set((state) => ({
   604→              xp: data.xp ?? state.xp,
   605→              level: data.level ?? state.level,
   606→              streak: data.streak ?? state.streak,
   607→              masteries: data.masteries ?? state.masteries,
   608→              achievements: data.achievements ?? state.achievements,
   609→              totalStudyMinutes: data.totalStudyMinutes ?? state.totalStudyMinutes,
   610→              questionsAsked: data.questionsAsked ?? state.questionsAsked,
   611→            }));
   612→          }
   613→
   614→          if (sessionsRes.ok) {
   615→            const sessions = await sessionsRes.json();
   616→            if (Array.isArray(sessions)) {
   617→              // Calculate sessionsThisWeek from DB sessions
   618→              const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
   619→              const recentCount = sessions.filter(
   620→                (s: StudySession) => new Date(s.startedAt) > weekAgo
   621→              ).length;
   622→
   623→              set({
   624→                sessionHistory: sessions.map((s: StudySession) => ({
   625→                  ...s,
   626→                  id: `synced-${s.id}`, // Mark as synced
   627→                  startedAt: new Date(s.startedAt),
   628→                  endedAt: s.endedAt ? new Date(s.endedAt) : undefined,
   629→                })),
